// ============================================================
// CHECKS REGISTRY
// Add new capabilities HERE ONLY. Never modify the logic below.
// Fields:
//   env          - required env var names (checked against $env)
//   instructions - human-readable setup steps sent to operator
//   onboarding_workflow - optional n8n workflow name to execute for guided setup
// ============================================================
const CHECKS = {

  // ── Communications channels ──
  telegram: {
    env: ['TELEGRAM_BOT_TOKEN', 'APPROVAL_CHAT_ID'],
    instructions: 'Set TELEGRAM_BOT_TOKEN and APPROVAL_CHAT_ID in /opt/n8n.env (or Infisical), then restart n8n. Ensure the Telegram Bot credential is configured in n8n Settings > Credentials.',
    onboarding_workflow: '[YAOC2] Onboarding — Capability: Telegram'
  },
  whatsapp: {
    env: ['EVOLUTION_API_URL', 'EVOLUTION_API_KEY', 'EVOLUTION_INSTANCE_NAME', 'WHATSAPP_PHONE'],
    instructions: 'Set EVOLUTION_API_URL, EVOLUTION_API_KEY, EVOLUTION_INSTANCE_NAME, and WHATSAPP_PHONE in /opt/n8n.env. Ensure Evolution API is running and the WhatsApp instance is connected and paired.',
    onboarding_workflow: '[YAOC2] Onboarding — Capability: WhatsApp'
  },
  slack: {
    env: ['SLACK_BOT_TOKEN', 'SLACK_SIGNING_SECRET', 'SLACK_DEFAULT_CHANNEL'],
    instructions: 'Create a Slack app at api.slack.com/apps. Add Bot Token Scopes: chat:write, channels:read, channels:history. Install to workspace. Set SLACK_BOT_TOKEN (xoxb-...), SLACK_SIGNING_SECRET, and SLACK_DEFAULT_CHANNEL in /opt/n8n.env.',
    onboarding_workflow: '[YAOC2] Onboarding — Capability: Slack'
  },

  // ── Google services ──
  // Note: google_ai uses API key (env var). gmail and google_calendar use OAuth2
  // credentials configured in n8n — env vars here are used as a presence signal
  // since n8n OAuth tokens are not accessible via $env.
  google_ai: {
    env: ['GOOGLE_AI_API_KEY'],
    instructions: 'Get a Gemini API key at aistudio.google.com/apikey. Set GOOGLE_AI_API_KEY in /opt/n8n.env. In n8n Settings > Credentials, create a Google AI credential using this key. Supports Gemini 1.5 Pro, Gemini 2.0 Flash, etc.',
    onboarding_workflow: '[YAOC2] Onboarding — Capability: LLM Provider'
  },
  gmail: {
    env: ['GOOGLE_OAUTH_CLIENT_ID', 'GOOGLE_OAUTH_CLIENT_SECRET'],
    instructions: 'Create an OAuth2 app in Google Cloud Console (console.cloud.google.com). Enable Gmail API. Add GOOGLE_OAUTH_CLIENT_ID and GOOGLE_OAUTH_CLIENT_SECRET to /opt/n8n.env. Then create a Gmail OAuth2 credential in n8n Settings > Credentials and complete the OAuth flow.',
    onboarding_workflow: '[YAOC2] Onboarding — Capability: Google OAuth'
  },
  google_calendar: {
    env: ['GOOGLE_OAUTH_CLIENT_ID', 'GOOGLE_OAUTH_CLIENT_SECRET'],
    instructions: 'Same OAuth2 app as Gmail (console.cloud.google.com). Enable Google Calendar API. GOOGLE_OAUTH_CLIENT_ID and GOOGLE_OAUTH_CLIENT_SECRET must be set. Create a Google Calendar OAuth2 credential in n8n and complete the OAuth flow.',
    onboarding_workflow: '[YAOC2] Onboarding — Capability: Google OAuth'
  },

  // ── LLM providers ──
  // openai-compat covers: OpenAI, Groq, Mistral, OpenRouter, Ollama, LM Studio,
  // LiteLLM, vLLM, DeepSeek (via compat endpoint), Claude via proxy, etc.
  // Set OPENAI_COMPAT_BASE_URL to the provider's /v1 endpoint.
  'openai-compat': {
    env: ['OPENAI_COMPAT_BASE_URL', 'OPENAI_COMPAT_KEY'],
    instructions: 'Set OPENAI_COMPAT_BASE_URL (e.g. https://api.openai.com/v1, https://api.groq.com/openai/v1, http://localhost:11434/v1 for Ollama) and OPENAI_COMPAT_KEY in /opt/n8n.env. In n8n, create an OpenAI credential and override the Base URL field to match OPENAI_COMPAT_BASE_URL.',
    onboarding_workflow: '[YAOC2] Onboarding — Capability: LLM Provider'
  },
  deepseek: {
    env: ['DEEPSEEK_API_KEY'],
    instructions: 'Set DEEPSEEK_API_KEY in /opt/n8n.env or Infisical. DeepSeek uses an OpenAI-compatible endpoint at https://api.deepseek.com/v1 — you can also route this through openai-compat with OPENAI_COMPAT_BASE_URL=https://api.deepseek.com/v1.',
    onboarding_workflow: '[YAOC2] Onboarding — Capability: LLM Provider'
  },
  // anthropic_direct: use when calling Claude natively (claude.ai/api).
  // For Claude via OpenRouter or LiteLLM proxy, use openai-compat instead.
  anthropic_direct: {
    env: ['ANTHROPIC_API_KEY'],
    instructions: 'Get an API key at console.anthropic.com. Set ANTHROPIC_API_KEY in /opt/n8n.env. In n8n, create an Anthropic credential (n8n has a native Anthropic node) or use HTTP Header Auth with Authorization: x-api-key <key>. Alternatively, route Claude through OpenRouter using the openai-compat capability.',
    onboarding_workflow: '[YAOC2] Onboarding — Capability: LLM Provider'
  }

};
// ============================================================
// GUARD LOGIC — do not modify
// ============================================================

const capability = ($input.item.json.capability ?? '').toLowerCase().trim();

if (!capability) {
  return [{ json: {
    status: 'missing',
    missingFields: ['capability'],
    instructions: 'Pass a capability string as input. Valid values: ' + Object.keys(CHECKS).join(', '),
    onboarding_workflow: null
  } }];
}

const check = CHECKS[capability];
if (!check) {
  return [{ json: {
    status: 'missing',
    missingFields: ['capability'],
    instructions: `Unknown capability '${capability}'. Valid values: ${Object.keys(CHECKS).join(', ')}.`,
    onboarding_workflow: null
  } }];
}

const missingFields = check.env.filter(envVar => {
  const val = $env[envVar];
  return !val || val.trim() === '';
});

if (missingFields.length > 0) {
  return [{ json: {
    status: 'missing',
    capability,
    missingFields,
    instructions: check.instructions,
    onboarding_workflow: check.onboarding_workflow
  } }];
}

return [{ json: { status: 'ok', capability, checkedFields: check.env } }];
